sql_query:
SELECT "Total sample size"
FROM clinical_trials
WHERE "Name of ICI" = 'Nivolumab, Ipilimumab';

ground_truth_sql:
WITH base AS (
SELECT "NCT", "PubMed ID", "Trial name", "Total sample size" AS source_value FROM clinical_trials
WHERE "Name of ICI" = 'Nivolumab, Ipilimumab'
)
SELECT "NCT", "PubMed ID", "Trial name", source_value, derive_size_bucket(source_value) AS "size_bucket"
FROM base;
